sql:
SELECT AVG(rating_value) AS average_performance_rating
FROM device_reviews_ratings
WHERE rating_name = 'Performance';

SELECT COUNT(*) AS number_of_devices_with_primary_image
FROM device_images
WHERE is_primary = 1;

external_knowledge:
; 

*   NULL values in the average rating column indicate that a device has no rating; 
*   Average rating is used as a measure of the overall satisfaction or quality of a device; 
*   Ordering devices by their average rating in descending order helps to identify top-rated devices.
